/**
 * Compatibility barrel for frontend types.
 *
 * Enum / string-union types are re-exported directly from the generated Specta
 * bindings (no field-naming issue).
 *
 * Struct-like types are defined here with **snake_case** field names to match
 * the existing frontend fixtures, mocks, and component code.  When the real
 * Tauri backend is wired (returning camelCase payloads), a follow-up task will
 * migrate all field accesses and switch these to re-exports of the generated
 * `_Serialize` variants.
 *
 * Types that only exist on the frontend side (not generated by Specta) are
 * defined at the bottom of this file.
 */

// ─── Enum / String-Union Re-exports ─────────────────────────────────────────

export type {
  SessionState,
  ProjectState,
  ConfidenceLevel,
  ProvenanceOrigin,
  ViewMode,
  Density,
  CalibrationKind,
  PlanItemAction,
  PlanItemState,
  PlanItemProtection,
  PlanOrigin,
  PlanType,
  DestructiveDestination,
  AuditOutcome,
  ReviewItemKind,
  SearchResultKind,
  TargetKind,
  RootCategory,
  // Spec 008: project source role + selection (canonical in projects_v2.rs)
  SourceRole,
  SourceSelection,
  // SourceViewStrategy — moved to spec 026 (generated source views); remove this
  //   re-export when spec 026 registers its command and emits the type.
  // OutputVerification  — moved to spec 012 (artifact verification); same.
  // CleanupEligibility  — moved to spec 017 cleanup planner; same.
  SessionsGroupBy,
  SessionsView,
  TransitionActor,
  TransitionStatus,
  AuditActor,
  AssetType,
  // Plan response types
  PlanApproveResponse,
  PlanDiscardResponse,
  PlanRetryResponse,
  ArchiveSendToTrashResponse,
  ArchivePermanentlyDeleteResponse,
} from './index';

/**
 * PlanState — re-export from generated bindings. Includes `"paused"` (spec 017
 * data-model.md §PlanState, R-Pause-1) now that it is surfaced in the Rust
 * contracts `PlanState` enum.
 */
export type PlanState = import('./index').PlanState;

// ─── Struct Interfaces ───────────────────────────────────────────────────────
//
// Types with a generated _Serialize equivalent are now simple re-exports so
// that consumers and the generated bindings share one structural type.
// The follow-up task (T111) migrated all field accesses in components,
// fixtures, and mocks from snake_case to camelCase.

export interface MetaValue {
  value: unknown;
  raw?: string;
  origin: import('./index').ProvenanceOrigin;
  confidence: import('./index').ConfidenceLevel;
  evidence_ref?: string;
}

export interface AppPreferences {
  sidebarCollapsed: boolean;
  density: import('./index').Density;
  projectViewModes: Record<string, import('./index').ViewMode>;
  defaultProjectView: import('./index').ViewMode;
  sessionsGroupBy: 'none' | 'target' | 'month' | 'filter' | 'train';
  sessionsView: 'list' | 'calendar';
  tourCompleted: { step1: boolean; step2: boolean; step3: boolean };
  setupCompleted: boolean;
}

export interface SourceMap {
  lights: string[];
  darks: string[];
  flats: string[];
  bias: string[];
  dark_flats: string[];
}

export interface SettingsData {
  [key: string]: unknown;
}

